import{_ as t,o as a,c as o,aq as n}from"./chunks/framework.DH0nG2Fl.js";const u=JSON.parse('{"title":"First Edits","description":"","frontmatter":{"prev":{"text":"Your first Extension","link":"/development/extensions/start"},"next":{"text":"Tooling","link":"/development/tooling"}},"headers":[],"relativePath":"development/extensions/first-edits.md","filePath":"development/extensions/first-edits.md","lastUpdated":1782431519000}'),i={name:"development/extensions/first-edits.md"};function s(r,e,l,c,h,d){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="first-edits" tabindex="-1">First Edits <a class="header-anchor" href="#first-edits" aria-label="Permalink to “First Edits”">​</a></h1><p>Here, we will see the common files that are in all of the extensions and we will edit them to make this extension ours!</p><h2 id="how-does-an-extension-work" tabindex="-1">How does an extension work? <a class="header-anchor" href="#how-does-an-extension-work" aria-label="Permalink to “How does an extension work?”">​</a></h2><p>First let&#39;s look at what files are in this extension :</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>./static</span></span>
<span class="line"><span>./static/icon.png</span></span>
<span class="line"><span>./content.json</span></span>
<span class="line"><span>./forms.ts</span></span>
<span class="line"><span>./main.ts</span></span>
<span class="line"><span>./models.ts</span></span>
<span class="line"><span>./network.ts</span></span>
<span class="line"><span>./pbconfig.ts</span></span></code></pre></div><p>When you first download the extension, you need to provide to Paperback all of the informations, and this is what the <code>pbconfig.ts</code> file is for.</p><h3 id="pbconfig-ts" tabindex="-1">pbconfig.ts <a class="header-anchor" href="#pbconfig-ts" aria-label="Permalink to “pbconfig.ts”">​</a></h3><p>We can see that this files export an object (that satisfies the type <code>ExtensionInfo</code>) that resumne all of the surface info of the extension</p><h4 id="name" tabindex="-1">Name <a class="header-anchor" href="#name" aria-label="Permalink to “Name”">​</a></h4><p>You can now edit the <code>name</code> of the app, it can contain spaces but it&#39;s betten if there are none and if the app name is the same then the name of the directory where the code lives. Also, do not put the whole url as the name, for exemple : <code>mangakatana.com</code> --&gt; <code>MangaKatana</code></p><h4 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to “Description”">​</a></h4><p>For the <code>description</code> part, you could also technically put anything in there but the common syntax for Inkdex is : <code>Extension that pulls content from mangakatana.com.</code></p><h4 id="version" tabindex="-1">Version <a class="header-anchor" href="#version" aria-label="Permalink to “Version”">​</a></h4><p>The <code>version</code> string is very important, you should know that Paperback alows you to &quot;update&quot; from any 2 extensions with the same name as long as the version string is different even when it&#39;s a lower version. It&#39;s important because you might have different extension repositories with differrent version of you extension (the latest one on your PC, the stable one on GitHub etc...) so be carefull and do not update everytime you&#39;re prompted to. When you will want to debug something on your phone, you don&#39;t have to bump the version everytime, you can just hit reload it reinstalls it.</p><h4 id="icon" tabindex="-1">Icon <a class="header-anchor" href="#icon" aria-label="Permalink to “Icon”">​</a></h4><p>For the <code>icon</code> attributes, I will let the Paperback comment explain this one :</p><blockquote><p>An INTERNAL reference to an icon which is associated with this source. This Icon should ideally be a matching aspect ratio (a cube) The location of this should be in an includes directory next to your source.</p><p>... (<code>@paperback/type/lib/impl/SourceInfo.d.ts:86</code>)</p></blockquote><p>This just means, in the directory of your extension, you should have a <code>static</code> dir, with an icon, and you should put only the filename of this icon inside the <code>icon</code> attributes.</p><p>At Inkdex we preffer square png with only a simple logo and not the fullname of the website</p><h4 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to “Language”">​</a></h4><p>It&#39;s not technically required, but it cost nothing to add it. If your website only provides english content : <code>en</code>, if there are multiple langages : <code>multi</code>, and if there is only spanish content <code>es</code>. Please follow the lowercase version of <a href="https://wikipedia.org/wiki/ISO_3166-1_alpha-2" target="_blank" rel="noreferrer">ISO 3166-1 alpha-2</a></p><h4 id="content-rating" tabindex="-1">Content Rating <a class="header-anchor" href="#content-rating" aria-label="Permalink to “Content Rating”">​</a></h4><blockquote><p>A content rating attributed to each source. This can be one of three values, and should be set appropriately.</p><p>Everyone: This source does not have any sort of adult content available. Each title within is assumed safe for all audiences</p><p>Mature: This source MAY have mature content inside of it. Even if most content is safe, mature should be selected even if a small subset applies</p><p>Adult: This source probably has straight up pornography available.</p><p>This rating helps us filter your source to users who have the necessary visibility rules toggled for their profile. Naturally, only &#39;Everyone&#39; sources will show up for users without an account, or without any mode toggles changed.</p><p>(<code>@paperback/type/lib/impl/SourceInfo.d.ts:101</code>)</p></blockquote><h4 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to “Capabilities”">​</a></h4><p>This is the most important part of this file, it dictates everything that the extension can and cannot do, it&#39;s a list of <code>enums SourceIntents</code>, possibilities are the following :</p><ul><li><code>NONE</code> - the extension does nothing.</li><li><code>CHAPTER_PROVIDING</code> - You can read a chapter when asked to.</li><li><code>PROGRESS_PROVIDING</code> - ??</li><li><code>DISCOVER_SECTION_PROVIDING</code> - Can provide a homepage for your website in the Home section.</li><li><code>MANAGED_COLLECTION_PROVIDING</code> - ??</li><li><code>CLOUDFLARE_BYPASS_PROVIDING</code> - Your extension can use the CloudFlare bypassing tools</li><li><code>SETTINGS_FORM_PROVIDING</code> - Your extension provides a special settings page called the Settings form.</li><li><code>SEARCH_RESULT_PROVIDING</code> - Your can search stuff with your extension. Either a simple sort or even with advanced filters.</li></ul>`,26)])])}const f=t(i,[["render",s]]);export{u as __pageData,f as default};
